// ─── CONFIGURE YOUR HASHTAGS HERE ───────────────────────
const HASHTAGS = [ 
  'retrogames', 
  'ps2games'
];

const MAX_POSTS_PER_TAG = 10; // how many posts to fetch per hashtag

return HASHTAGS.map(tag => ({
  json: { hashtag: tag, maxPosts: MAX_POSTS_PER_TAG }
}));

// 1. Get ALL incoming items that fetched from the API
const allInputItems = $input.all();
const hashtag = $('Set Hashtags').item.json.hashtag; // Fallback fallback tag tracking

let allParsedPosts = [];

// 2. Loop through each API result item safely
for (const item of allInputItems) {
  const raw = item.json;

  let posts = [];
  if (Array.isArray(raw)) {
    posts = raw;
  } else if (Array.isArray(raw?.items)) {
    posts = raw.items;
  } else if (Array.isArray(raw?.data)) {
    posts = raw.data;
  } else if (Array.isArray(raw?.results)) {
    posts = raw.results;
  } else if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
    posts = [raw];
  }

  if (posts.length === 0) {
    continue;
  }

  // 3. Map individual entries to your formatting
  const mapped = posts.map(post => ({
    json: {
      id:        post.id || post.shortCode || post.pk || '',
      shortcode: post.shortCode || post.id || '',
      url:       post.url || `https://www.instagram.com/p/${post.shortCode || post.id}/`,
      thumbnail: post.displayUrl || post.thumbnailSrc || '',
      caption:   (post.caption || post.accessibility_caption || '').slice(0, 200),
      likes:     Number(post.likesCount || 0),
      comments:  Number(post.commentsCount || 0),
      saves:     Number(post.savesCount || 0),
      reposts:   Number(post.videoViewCount || post.videoPlayCount || 0),
      timestamp: post.timestamp || '',
      author:    post.ownerUsername || post.ownerFullName || 'unknown',
      hashtag:   hashtag, // Maps back to the workflow contextual tag
      type:      post.type || post.productType || 'image'
    }
  }));

  allParsedPosts.push(...mapped);
}

if (allParsedPosts.length === 0) {
  return [{ json: { _empty: true, hashtag, _debug_raw: "No items parsed from any run." } }];
}

return allParsedPosts;

// ─── ENGAGEMENT SCORE FORMULA ──────────────────────────────────────
// Weights reflect content signal value:
//   reposts  = 4  (strongest signal — someone shares it)
//   comments = 3  (high intent — someone typed)
//   saves    = 2  (bookmarks = future intent)
//   likes    = 1  (lowest friction)

const W = { reposts: 4, comments: 3, saves: 2, likes: 1 };

const items = $input.all();

// Deduplicate by post ID (across hashtags)
const seen = new Set();
const unique = items.filter(item => {
  const id = item.json.id || item.json.shortcode;
  if (!id || seen.has(id)) return false;
  seen.add(id);
  return !item.json._empty;
});

// Score each post
const scored = unique.map(item => {
  const p = item.json;
  const score = Math.round(
    (p.likes    || 0) * W.likes    +
    (p.comments || 0) * W.comments +
    (p.saves    || 0) * W.saves    +
    (p.reposts  || 0) * W.reposts
  );

  // Normalise timestamp
  let postedAt = '';
  if (p.timestamp) {
    const ts = typeof p.timestamp === 'number' ? p.timestamp * 1000 : new Date(p.timestamp).getTime();
    postedAt = new Date(ts).toISOString();
  }

  return {
    json: {
      ...p,
      score,
      postedAt,
      scannedAt: new Date().toISOString()
    }
  };
});

// Sort descending by score
scored.sort((a, b) => b.json.score - a.json.score);

// Return top 10
return scored.slice(0, 10);

// Build a compact HTML report for Telegram (parse_mode: HTML)
const posts = $input.all();
const now = new Date().toUTCString();

const hashtags = [...new Set(posts.map(p => p.json.hashtag))]
  .map(h => `#${h}`).join(' ');

const rows = posts.map((item, i) => {
  const p = item.json;
  const medal = ['🥇','🥈','🥉'][i] || `${i+1}.`;
  const caption = p.caption ? p.caption.replace(/</g,'&lt;').replace(/>/g,'&gt;').slice(0,80) + '…' : '(no caption)';
  const postedDate = p.postedAt ? new Date(p.postedAt).toLocaleDateString('en-GB', { day:'numeric', month:'short' }) : '—';

  return (
    `${medal} <a href="${p.url}">@${p.author}</a>  <b>Score: ${p.score.toLocaleString()}</b>\n` +
    `   👍 ${(p.likes||0).toLocaleString()}  💬 ${(p.comments||0).toLocaleString()}  🔖 ${(p.saves||0).toLocaleString()}  🔁 ${(p.reposts||0).toLocaleString()}\n` +
    `   📅 ${postedDate}  |  ${p.type || 'post'}\n` +
    `   <i>${caption}</i>\n`
  );
}).join('\n');

const message =
  `<b>📊 Instagram Engagement Report</b>\n` +
  `${hashtags}\n` +
  `<i>Generated: ${now}</i>\n\n` +
  rows +
  `\n<i>Top 10 by weighted score (reposts×4 · comments×3 · saves×2 · likes×1)</i>`;

return [{ json: { message } }];
